declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';if($_SERVER['REQUEST_METHOD']!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$accion=(string)($_POST['accion']??'');$comentario=trim(strip_tags((string)($_POST['comentario']??'')));try{if($accion==='publicar')publicarWebsite(obtenerConexion(),(int)$_SESSION['usuario_id'],$comentario);elseif($accion==='descartar')descartarBorradorWebsite(obtenerConexion(),(int)$_SESSION['usuario_id']);elseif($accion==='restaurar'){restaurarVersionWebsite(obtenerConexion(),cmsId($_POST['version_id']??0),(int)$_SESSION['usuario_id']);}else throw new DomainException('Acción inválida.');cmsFlash('success',$accion==='publicar'?'Cambios publicados.':'Borrador actualizado.');}catch(Throwable$e){cmsFlash('danger',$e instanceof DomainException?$e->getMessage():'No fue posible completar la acción.');}header('Location:editor.php');exit;
